mapper.select:
SELECT MIN(p.id) AS id, r.id AS register_id, r.patient_id AS patient_id, r.real_name AS patient_name, r.employee_id AS physician_id, e.realname AS physician_name, MAX(p.diagnosis) AS diagnosis, SUM(COALESCE(d.price, 0) * ()) AS total_amount, CASE WHEN COUNT(*) FILTER (WHERE p.drug_state = '未发') = 0 AND COUNT(*) FILTER (WHERE p.drug_state = '已退') = 0 THEN 1 WHEN COUNT(*) FILTER (WHERE p.drug_state = '已退') > 0 THEN 2 ELSE 0 END AS dispensation_status, MAX(p.dispensation_time) AS dispensation_time, MAX(p.pharmacist) AS pharmacist, MAX(p.remarks) AS remarks, MIN(p.creation_time) AS create_time FROM prescription p INNER JOIN register r ON r.id = p.register_id LEFT JOIN employee e ON e.id = r.employee_id LEFT JOIN drug_info d ON d.id = p.drug_id
r.patient_id = #{patientId}
AND p.creation_time >= #{startDate}
AND p.creation_time <= #{endDate}
GROUP BY r.id, r.patient_id, r.real_name, r.employee_id, e.realname
HAVING COUNT(*) FILTER (WHERE p.drug_state <> '已发') = 0
HAVING COUNT(*) FILTER (WHERE p.drug_state <> '已退') = 0
HAVING COUNT(*) FILTER (WHERE p.drug_state = '未发') > 0
ORDER BY create_time DESC

SELECT MIN(p.id) AS id, r.id AS register_id, r.patient_id AS patient_id, r.real_name AS patient_name, r.employee_id AS physician_id, e.realname AS physician_name, MAX(p.diagnosis) AS diagnosis, SUM(COALESCE(d.price, 0) * ()) AS total_amount, 0 AS dispensation_status, MAX(p.dispensation_time) AS dispensation_time, MAX(p.pharmacist) AS pharmacist, MAX(p.remarks) AS remarks, MIN(p.creation_time) AS create_time FROM prescription p INNER JOIN register r ON r.id = p.register_id LEFT JOIN employee e ON e.id = r.employee_id LEFT JOIN drug_info d ON d.id = p.drug_id
p.register_id = #{registrationId}
GROUP BY r.id, r.patient_id, r.real_name, r.employee_id, e.realname HAVING COUNT(*) FILTER (WHERE p.drug_state = '未发') > 0 ORDER BY create_time ASC

mapper.update:
UPDATE prescription
SET drug_state = #{stateText}
WHERE id = #{id}

UPDATE prescription
SET drug_state        = #{newStateText},
    dispensation_time = #{dispensationTime},
    pharmacist        = #{pharmacist}
WHERE register_id = #{registerId}
  AND drug_state  = #{oldStateText}
